// Top of the file
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const ModeratorDashboard = () => {
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [editUser, setEditUser] = useState(null); // For editing
  const [editData, setEditData] = useState({ username: '', role: '', email: '' });

  const navigate = useNavigate();
  const token = localStorage.getItem('accessToken');

  useEffect(() => {
    if (!token) {
      setError('No token found. Please log in again.');
      navigate('/login');
      return;
    }

    fetch('http://localhost:8000/api/manage-users/', {
      headers: { 'Authorization': `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setUsers(data);
        else setError('Invalid response format');
      })
      .catch(() => setError('Failed to load users.'));
  }, [navigate, token]);

  const deleteUser = (id) => {
    fetch(`http://localhost:8000/api/manage-users/${id}/`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    }).then(() => {
      setUsers(users.filter(user => user.id !== id));
    });
  };

  const handleEditClick = (user) => {
    setEditUser(user);
    setEditData({ username: user.username, role: user.role, email: user.email });
  };

  const handleEditChange = (e) => {
    setEditData({ ...editData, [e.target.name]: e.target.value });
  };

  const handleUpdateUser = () => {
    fetch(`http://localhost:8000/api/manage-users/${editUser.id}/`, {
      method: 'PUT',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(editData),
    })
      .then(res => res.json())
      .then(updated => {
        const newUsers = users.map(u => (u.id === updated.id ? updated : u));
        setUsers(newUsers);
        setEditUser(null);
      })
      .catch(() => alert('Update failed.'));
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Moderator Dashboard</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}

      <table border="1" cellPadding="8" style={{ width: '100%' }}>
        <thead>
          <tr>
            <th>ID</th><th>Username</th><th>Role</th><th>Email</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map(u => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.username}</td>
              <td>{u.role}</td>
              <td>{u.email}</td>
              <td>
                <button onClick={() => deleteUser(u.id)}>Delete</button>
                <button onClick={() => handleEditClick(u)}>Edit</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {editUser && (
        <div style={{ marginTop: 20 }}>
          <h3>Edit User #{editUser.id}</h3>
          <input
            name="username"
            value={editData.username}
            onChange={handleEditChange}
            placeholder="Username"
          />
          <select name="role" value={editData.role} onChange={handleEditChange}>
            <option value="student">Student</option>
            <option value="teacher">Teacher</option>
            <option value="moderator">Moderator</option>
          </select>
          <input
            name="email"
            value={editData.email}
            onChange={handleEditChange}
            placeholder="Email"
          />
          <button onClick={handleUpdateUser}>Save</button>
          <button onClick={() => setEditUser(null)}>Cancel</button>
        </div>
      )}
    </div>
  );
};

export default ModeratorDashboard;
